                next.push([row, col - 1]);
                seen[row][col - 1] = true;
            }
            if (col + 1 < cols && !seen[row][col + 1]) {
                next.push([row, col + 1]);
                seen[row][col + 1] = true;
            }
        }

        stack = next;
        manDist++;
    }

    let minSeen = 0;

    const dfs = (row, col, min) => {
        if (row < 0 || col < 0 || row > rows - 1 || col > cols -1 ||
            grid[row][col] === -1 || min <= minSeen) {
            return;
        }
        if (row === rows - 1 && col === cols - 1) {
            minSeen = Math.max(minSeen, Math.min(min, grid[row][col]));
            return;
        }

        const manDist = grid[row][col];
        if (manDist < min) {
            min = manDist;
        }

        grid[row][col] = -1;

        let arr = [
            [row, col + 1],
            [row + 1, col],
            [row, col - 1],
            [row - 1, col],
        ].filter(([row, col]) => row >= 0 && col >= 0 && row < rows && col < cols);

        arr.sort((a, b) => grid[b[0]][b[1]] - grid[a[0]][a[1]]);

        arr = arr.map(([row, col]) => dfs(row, col, min));

        grid[row][col] = manDist;
    };

    dfs(0, 0, grid[0][0]);

    return minSeen;
};

